vectors.script:
export const meta = { name: 'simple-agent', description: 'callId vector', phases: [{ title: 'main' }] }
phase('main')
const a = await agent('summarize the input')
return { a }

export const meta = { name: 'schema-agent', description: 'callId vector', phases: [{ title: 'main' }] }
const a = await agent('extract fields', { schema: { type: 'object', properties: { title: { type: 'string' } } }, label: 'extract' })
return { a }

export const meta = { name: 'dup-agent', description: 'callId vector', phases: [{ title: 'main' }] }
const r = await parallel([
  () => agent('do it', { label: 'L' }),
  () => agent('do it', { label: 'L' }),
  () => agent('do it', { label: 'L' }),
])
return { r }

export const meta = { name: 'labeled-pipeline', description: 'callId vector', phases: [{ title: 'main' }] }
const r = await pipeline(['x', 'y'],
  async (item) => await agent('stage-one', { label: 'first:' + item }),
  async (val) => await agent('stage-two', { label: 'second' }),
)
return { r }

export const meta = { name: 'workflow-call', description: 'callId vector', phases: [{ title: 'main' }] }
const r = await workflow('child-report', { region: 'emea', year: 2026 })
return { r }

export const meta = { name: 'parallel-batch', description: 'callId vector', phases: [{ title: 'main' }] }
const r = await parallel([
  () => agent('alpha'),
  () => agent('beta'),
  () => agent('gamma'),
])
return { r }
